1	const scaleHorizontally = (line: string, scaleFactor: number): string =>
2	  line.split("").map((char) => char.repeat(scaleFactor)).join("");
3	
4	const scaleHorizontalLines = (lines: string[], scaleFactor: number): string[] =>
5	  lines.map((line) => scaleHorizontally(line, scaleFactor));
6	
7	const duplicateLines = (lines: string[], count: number): string[] => {
8	  const result: string[] = [];
9	  for (const line of lines) {
10	    for (let i = 0; i < count; i++) {
11	      result.push(line);
12	    }
13	  }
14	  return result;
15	};
16	
17	export function scale(image: string[], scaleFactor: number): string[] {
18	  if (image.length === 0) {
19	    return [];
20	  }
21	
22	  const isMultiRowMultiCol = image.length > 1 && image[0].length > 1;
23	
24	  if (isMultiRowMultiCol) {
25	    // Scale both horizontally and vertically
26	    const horizontallyScaled = scaleHorizontalLines(image, scaleFactor);
27	    return duplicateLines(horizontallyScaled, scaleFactor);
28	  }
29	
30	  const isSingleColumn = image.length > 1 && image.every((line) => line.length === 1);
31	
32	  if (isSingleColumn) {
33	    // Scale vertically only
34	    return duplicateLines(image, scaleFactor);
35	  }
36	
37	  // Default: scale horizontally only
38	  return scaleHorizontalLines(image, scaleFactor);
39	}
